import { useMemo, useCallback } from "react";
import { Landmark } from "lucide-react";
import { useTranslation } from "react-i18next";
import TranslatableText from "@/components/TranslatableText";

// I Ching multi-language detection patterns
const iChingPatterns = [
  /(.*?)((?:这恰如|恰如|正如|这正如|这如同|如同|犹如|宛如)《易经[\s\S]*$)/s,
  /(.*?)(《易经[\s\S]*$)/s,
  /(.*?)((?:This echoes|This resonates|As the|This is akin to|This reflects|Much like|Just as)[\s\S]*?(?:I Ching|Book of Changes|Yi Jing)[\s\S]*$)/si,
  /(.*?)((?:I Ching|Book of Changes|Yi Jing)\s*(?:hexagram|quote|says|states|teaches|reminds|"|\()[\s\S]*$)/si,
  /(.*?)((?:Isso ecoa|Isso ressoa|Como o|Assim como|Tal como)[\s\S]*?(?:I Ching|Livro das Mutações)[\s\S]*$)/si,
  /(.*?)((?:I Ching|Livro das Mutações)\s*(?:hexagrama|diz|ensina|"|\()[\s\S]*$)/si,
  /(.*?)((?:كتاب التغيرات|كتاب التغييرات)[\s\S]*$)/s,
  /(.*?)(\(I Ching\)[\s\S]*$)/si,
  /(.*?)((?:Yi King|Livre des Mutations)[\s\S]*$)/si,
  /(.*?)((?:Libro de los Cambios)[\s\S]*$)/si,
  /(.*?)((?:I Ging|Buch der Wandlungen)[\s\S]*$)/si,
  /(.*?)((?:易経)[\s\S]*$)/s,
  /(.*?)((?:주역|역경)[\s\S]*$)/s,
  /(.*?)((?:И Цзин|Книга Перемен)[\s\S]*$)/si,
  /(.*?)((?:Libro dei Mutamenti)[\s\S]*$)/si,
  /(.*?)((?:Hexagram|hexagrama|Hexagramm|hexagramme)\s*\d+[\s\S]*$)/si,
];

function splitStory(text: string): { main: string; iching: string | null } {
  for (const pattern of iChingPatterns) {
    const match = text.match(pattern);
    if (match && match[1].trim().length > 0) {
      return { main: match[1].trim(), iching: match[2].trim() };
    }
  }
  return { main: text, iching: null };
}

/** Detect if address is in a Portuguese-speaking country */
const PT_COUNTRY_PATTERN = /portugal|brasil|brazil|moçambique|mozambique|angola|cabo verde|são tomé|timor|macau|barreiro|lisboa|porto|faro|coimbra|braga|almada|amadora|setúbal|funchal|aveiro|leiria|évora|beja|guarda|viseu|bragança|santarém|cascais|sintra|oeiras|loures|seixal|gondomar|guimarães|odivelas|matosinhos|vila nova de gaia/i;

/** Export for reuse in Restaurants.tsx dialog */
export function getBuildingStoryParts(restaurant: {
  photo_story_zh?: string | null;
  photo_story_en?: string | null;
  photo_story_pt?: string | null;
  address?: string | null;
}) {
  const isPt = PT_COUNTRY_PATTERN.test(restaurant.address || "");
  const nativeStory = isPt
    ? (restaurant.photo_story_pt || restaurant.photo_story_en)
    : (restaurant.photo_story_en || restaurant.photo_story_pt);

  // I Ching always from Chinese version
  const zhStory = restaurant.photo_story_zh || "";
  const { iching: iChingChinese } = splitStory(zhStory);

  // Building narrative (strip any I Ching from native story)
  const { main: buildingNarrative } = nativeStory ? splitStory(nativeStory) : { main: "" };

  return { buildingNarrative, iChingChinese };
}

// Separator used to combine narrative + I Ching for single translate button
const SEPARATOR = "\n\n---ICHING_SEPARATOR---\n\n";

interface BuildingStorySectionProps {
  restaurant: {
    photo_story_zh?: string | null;
    photo_story_en?: string | null;
    photo_story_pt?: string | null;
    address?: string | null;
  };
  variant?: "section" | "card";
}

export const BuildingStorySection = ({ restaurant, variant = "section" }: BuildingStorySectionProps) => {
  const { i18n } = useTranslation();

  const { buildingNarrative, iChingChinese } = useMemo(
    () => getBuildingStoryParts(restaurant),
    [restaurant.photo_story_zh, restaurant.photo_story_en, restaurant.photo_story_pt, restaurant.address]
  );

  // Combine for single translate button
  const fullText = useMemo(() => {
    return [buildingNarrative, iChingChinese].filter(Boolean).join(SEPARATOR);
  }, [buildingNarrative, iChingChinese]);

  const renderContent = useCallback((displayText: string) => {
    const parts = displayText.split("---ICHING_SEPARATOR---");
    const narrativePart = (parts[0] || "").trim();
    const iChingPart = (parts[1] || "").trim();
    return (
      <>
        {narrativePart && (
          <p className="whitespace-pre-line text-sm md:text-base leading-[1.8] text-foreground/90">
            {narrativePart}
          </p>
        )}
        {iChingPart && (
          <div className="mt-4 pt-4 border-t border-border/50">
            <p className="text-xs font-medium text-muted-foreground mb-2 flex items-center gap-1.5">
              <span>☰</span>
              {i18n.language === "zh" ? "易经解读" : i18n.language === "pt" ? "Interpretação do I Ching" : "I Ching Interpretation"}
            </p>
            <p className="whitespace-pre-line text-sm leading-[1.8] text-foreground/80 italic">
              {iChingPart}
            </p>
          </div>
        )}
      </>
    );
  }, [i18n.language]);

  if (!fullText) return null;

  const sectionTitle = i18n.language === "zh"
    ? "建筑故事"
    : i18n.language === "pt"
    ? "História do Edifício"
    : "Building Story";

  if (variant === "card") {
    return (
      <div className="p-4 rounded-lg bg-muted/50 space-y-3">
        <h3 className="text-base font-semibold text-foreground flex items-center gap-2">
          <Landmark className="w-4 h-4 text-primary" />
          {sectionTitle}
        </h3>
        <TranslatableText text={fullText} className="building-story-text" renderContent={renderContent} />
      </div>
    );
  }

  return (
    <section className="py-8 md:py-12 lg:py-16">
      <div className="container mx-auto max-w-4xl px-4">
        <div className="text-center mb-6 md:mb-8 lg:mb-10">
          <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
            {i18n.language === "zh" ? "历史 · 建筑 · 餐饮" : i18n.language === "pt" ? "História · Arquitetura · Gastronomia" : "History · Architecture · Dining"}
          </p>
          <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground flex items-center justify-center gap-2 md:gap-3">
            <Landmark className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary" />
            {sectionTitle}
          </h2>
          <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
        </div>

        <div className="rounded-xl overflow-hidden shadow-lg md:shadow-xl border border-border/50">
          <div className="relative bg-gradient-to-br from-primary/90 via-primary-light/80 to-accent/85 px-6 py-4">
            <div
              className="absolute inset-0 opacity-[0.06]"
              style={{
                backgroundImage:
                  'url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.4\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")',
              }}
            />
            <div className="relative z-10 flex items-center gap-2">
              <span className="text-xl">🏛️</span>
              <span className="text-sm md:text-base font-medium text-primary-foreground/80">
                {i18n.language === "zh" ? "我们不只是记录餐厅，而是记录这个位置的历史" : i18n.language === "pt" ? "Não documentamos apenas restaurantes — documentamos a história de um lugar" : "We don't just document a restaurant — we document the history of a place"}
              </span>
            </div>
          </div>

          <div className="px-6 py-5 md:py-6 bg-background">
            <TranslatableText text={fullText} className="building-story-text" renderContent={renderContent} />
          </div>
        </div>
      </div>
    </section>
  );
};

export default BuildingStorySection;
